  const result = claim({
    items: [
      { type: "sword", material: "steel", enchantment: 0, cursed: false },
      { type: "rune", material: "steel", enchantment: 0, cursed: false },
      { type: "rune", material: "steel", enchantment: 0, cursed: false },
      { type: "rune", material: "steel", enchantment: 0, cursed: false },
